from prometheus_client import start_http_server, Gauge
import time
import os
import psycopg2
from psycopg2 import OperationalError

# Initialize Prometheus gauge
db_connection_gauge = Gauge('db_connection_health', 'Database connection health',
                             ['username', 'host', 'connection_string'])

def check_db_connection(username, password, host, dbname):
    try:
        connection = psycopg2.connect(user=username,
                                      password=password,
                                      host=host,
                                      database=dbname)
        connection.close()
        return 1  # Healthy
    except OperationalError:
        return 0  # Unhealthy

def main():
    start_http_server(8000)
    while True:
        username = os.getenv('DB_USERNAME')
        password = os.getenv('DB_PASSWORD')
        host = os.getenv('DB_HOST')
        dbname = os.getenv('DB_NAME')
        connection_string = f"postgresql://{username}@{host}/{dbname}"

        health = check_db_connection(username, password, host, dbname)
        db_connection_gauge.labels(username=username, host=host, connection_string=connection_string).set(health)

        time.sleep(60)

if __name__ == '__main__':
    main()